export enum SubscriptionPlan {
  FREE = 'free',
  BASIC = 'basic',
  PRO = 'pro',
}

export const PLAN_PROFESSIONAL_LIMITS: Record<SubscriptionPlan, number> = {
  [SubscriptionPlan.FREE]: 2,
  [SubscriptionPlan.BASIC]: 10,
  [SubscriptionPlan.PRO]: -1,
};
// -1 means unlimited

@Schema({ timestamps: true }) class Subscription:
- clinicId: Types.ObjectId — @Prop({ type: Types.ObjectId, ref: 'Clinic', required: true, unique: true })
- plan: SubscriptionPlan — @Prop({ type: String, enum: SubscriptionPlan, default: SubscriptionPlan.FREE })
- status: SubscriptionStatus — @Prop({ type: String, enum: SubscriptionStatus, default: SubscriptionStatus.TRIAL }) — import SubscriptionStatus from '../../clinics/schemas/clinic.schema'
- expiresAt: Date — @Prop({ type: Date, required: true })

export type SubscriptionDocument = Subscription & Document;
export const SubscriptionSchema = SchemaFactory.createForClass(Subscription);

